/**
 * MMS REST API
 *
 * Main Hono application setup with middleware and route registration.
 * Provides RESTful endpoints for the Metro Fleet Mileage Management System.
 *
 * Base URL: /api/v1
 * Authentication: Bearer JWT (when implemented)
 * Rate Limiting: 100 requests/minute per user (when implemented)
 *
 * @see specs/005-api.md
 */

import { Hono } from 'hono';
import { cors } from 'hono/cors';
import { logger as honoLogger } from 'hono/logger';
import { secureHeaders } from 'hono/secure-headers';
import { timing } from 'hono/timing';
import {
  requestContext,
  createErrorHandler,
  notFoundHandler,
  tracingMiddleware,
} from './middleware';
import { authRoutes, fleetRoutes, pmScheduleRoutes, mileageRoutes, optimizerRoutes, baselineRoutes, driftRoutes, manhourRoutes, canvasRoutes, costingRoutes, materialRoutes, scenarioRoutes, exportRoutes, integrationRoutes } from './routes';
import { success, type AppVariables } from './types';
import { logger } from '../lib/logging/logger';

/**
 * Create the main Hono application
 */
export function createApp(): Hono<{ Variables: AppVariables }> {
  const app = new Hono<{ Variables: AppVariables }>();

  // ==========================================================================
  // Global Middleware
  // ==========================================================================

  // Security headers
  app.use('*', secureHeaders());

  // CORS configuration
  app.use(
    '*',
    cors({
      origin: (origin) => {
        // Allow localhost for development
        if (!origin) return '';
        if (origin.includes('localhost') || origin.includes('127.0.0.1')) {
          return origin;
        }
        // Add production origins here
        return '';
      },
      allowMethods: ['GET', 'POST', 'PATCH', 'PUT', 'DELETE', 'OPTIONS'],
      allowHeaders: ['Content-Type', 'Authorization', 'X-Request-ID'],
      exposeHeaders: ['X-Request-ID', 'X-Response-Time'],
      maxAge: 3600,
      credentials: true,
    })
  );

  // Request ID and timing
  app.use('*', requestContext());

  // Server timing headers
  app.use('*', timing());

  // Request logging (development)
  if (process.env.NODE_ENV !== 'production') {
    app.use('*', honoLogger());
  }

  // OpenTelemetry tracing
  app.use('*', tracingMiddleware());

  // ==========================================================================
  // Health Endpoints (outside /api/v1)
  // ==========================================================================

  /**
   * GET /health
   *
   * Liveness probe - returns 200 if process is running.
   */
  app.get('/health', (c) => {
    return c.json({ status: 'healthy', timestamp: new Date().toISOString() });
  });

  /**
   * GET /ready
   *
   * Readiness probe - returns 200 if service is ready to accept traffic.
   * Should check database, Redis, and external service connections.
   */
  app.get('/ready', async (c) => {
    // TODO: Add actual health checks (DB, Redis, etc.)
    const checks = {
      database: 'healthy',
      redis: 'healthy',
      timestamp: new Date().toISOString(),
    };

    return c.json({ status: 'ready', checks });
  });

  // ==========================================================================
  // API v1 Routes
  // ==========================================================================

  const api = new Hono<{ Variables: AppVariables }>();

  /**
   * GET /api/v1
   *
   * API information endpoint.
   */
  api.get('/', (c) => {
    return c.json(
      success({
        name: 'MMS API',
        version: '1.0.0',
        description: 'Metro Fleet Mileage Management System API',
        documentation: '/api/v1/docs',
      })
    );
  });

  // Authentication Routes
  api.route('/', authRoutes);

  // Fleet Management Routes
  api.route('/', fleetRoutes);

  // PM Schedule Management Routes
  api.route('/', pmScheduleRoutes);

  // Mileage Management Routes
  api.route('/', mileageRoutes);

  // Optimizer Routes
  api.route('/', optimizerRoutes);

  // Baseline Management Routes
  api.route('/', baselineRoutes);

  // Drift Analysis Routes
  api.route('/', driftRoutes);

  // Man-hour Management Routes
  api.route('/', manhourRoutes);

  // Canvas Data Routes
  api.route('/', canvasRoutes);

  // Costing Routes
  api.route('/', costingRoutes);

  // Material Management Routes
  api.route('/', materialRoutes);

  // Scenario Management Routes
  api.route('/', scenarioRoutes);

  // Export Routes
  api.route('/', exportRoutes);

  // Integration Routes (Maximo, webhooks)
  api.route('/', integrationRoutes);

  // Mount API at /api/v1
  app.route('/api/v1', api);

  // ==========================================================================
  // Error Handling
  // ==========================================================================

  // Not found handler for unmatched routes
  app.notFound(notFoundHandler());

  // Global error handler
  app.onError(createErrorHandler());

  return app;
}

/**
 * Singleton app instance
 */
let appInstance: Hono<{ Variables: AppVariables }> | null = null;

/**
 * Get the Hono app instance (creates if not exists)
 */
export function getApp(): Hono<{ Variables: AppVariables }> {
  if (!appInstance) {
    appInstance = createApp();
    logger.info('MMS API initialized');
  }
  return appInstance;
}

/**
 * Export types for external use
 */
export type {
  SuccessResponse,
  ErrorResponse,
  PaginationMeta,
  AppVariables,
  AuthUser,
} from './types';
export { success, paginatedSuccess, error, ErrorCodes } from './types';

/**
 * API Middleware Exports
 *
 * Central export for all Hono middleware.
 */

export { requestContext, getRequestDuration, getRequestId } from './request-context';
export { createErrorHandler, notFoundHandler } from './error-handler';
export { tracingMiddleware, addUserContextToSpan } from './tracing';
export {
  authMiddleware,
  optionalAuthMiddleware,
  requireRole,
  requireDepotAccess,
  requirePermission,
  getAuthUser,
  requireAuthUser,
} from './auth';

